import React from "react";
import { Form, Col, Button } from "react-bootstrap";

function CreateDeck() {
  return (
    <div>
      <Form>
      <h1>Create Deck</h1>
        <Col>
          <Form.Label className="mt-1">Name</Form.Label>
          <Form.Control className="mt-1" placeholder="Deck Name" type="text"></Form.Control>
          <Form.Label className="mt-1">Description</Form.Label>
          <Form.Control className="mt-1"
            placeholder="Brief description of the deck"
            as="textarea"
          ></Form.Control>
          <Button className="mt-2 mr-1" variant="secondary">
            Cancel
          </Button>
          <Button className="mt-2 mr-1">Submit</Button>
        </Col>
      </Form>
    </div>
  );
}

export default CreateDeck;
